class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        def is_pal(s, l, r):
            while l < r and s[l] == s[r]:
                l += 1
                r -= 1
            return l >= r

        def check(a, b):
            l, r = 0, len(a) - 1
            while l < r and a[l] == b[r]:
                l += 1
                r -= 1
            return is_pal(a, l, r) or is_pal(b, l, r)

        return check(a, b) or check(b, a)
